mapper.select:
select * from community_bill
where owner_id = #{ownerId}
  or owner_name like concat('%', #{ownerName}, '%')
   or bill_type = #{billType}
   or bill_no = #{billNo}
   or status = #{status}
   or community_id = #{communityId}
   or building = #{building}
   or unit = #{unit}
   or room = #{room}
order by create_time desc
